INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'overview', 'Overview > Facts: IIT (ISM) Dhanbad is located in Dhanbad district, Jharkhand - 826004.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'overview', 'Overview > Facts: Formerly known as Indian School of Mines, established in 1926.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'overview', 'Overview > Facts: One of the oldest technical institutions in India.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Boys: Aquamarine Hostel — for 4th yr UG, 3rd yr UG (23E), 1st yr PhD (newly admitted July 2025), Integrated M.Tech (20E & 21E) + Dual Degree, Double Major.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Boys: Jasper Hostel — for 1st yr B.Tech including Prep, 8th yr PhD, 7th yr PhD, 6th-4th yr PhD, 2nd yr PhD, 1st yr PhD (shifted from Sapphire).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Boys: Amber Hostel — for 2nd yr UG (24E), 2nd yr MBA, 2nd yr M.Sc, 3rd/2nd yr M.Tech, 2nd yr MA, Internship M.Tech 2nd yr, 1st yr PhD (newly admitted July 2025), Summer sem backlog.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Boys: Topaz Hostel — for 5th yr PhD, 4th yr PhD, 2nd yr PhD, 1st yr PhD/MMS.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Boys: Sapphire Hostel — for 1st yr M.Tech, 2nd yr M.Sc Tech.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Boys: Diamond Hostel — for 3rd yr M.Sc, 1st yr M.A, 1st yr M.Sc Tech.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Boys Summary: 6 boys hostels — Aquamarine, Jasper, Amber, Topaz, Sapphire, Diamond.');
