INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Girls Summary: 3 girls hostels — Emerald, Opal, Ruby & Rosaline.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Dhanbad', 'hostels', 'Hostels > Sharing: Every hostel has 2 members per room except New Rosaline (1st, 2nd, 3rd year) which has 3 members per room.');
